package com.melodyrent.service;
import com.melodyrent.dto.BookingDtos.PriceQuote; import com.melodyrent.entity.Product; import com.melodyrent.repository.PricingRuleRepository; import lombok.RequiredArgsConstructor; import org.springframework.stereotype.Service; import java.math.*; import java.time.*;
@Service @RequiredArgsConstructor
public class PricingService {
  private final PricingRuleRepository rules;
  public PriceQuote quote(Product product, LocalDate start, LocalDate end){ if(!end.isAfter(start)) throw new IllegalArgumentException("End date must be after start date"); BigDecimal total=BigDecimal.ZERO; StringBuilder notes=new StringBuilder("Base + weekend/holiday/admin multipliers"); for(LocalDate d=start; d.isBefore(end); d=d.plusDays(1)){ BigDecimal multiplier=BigDecimal.ONE; if(d.getDayOfWeek()==DayOfWeek.SATURDAY || d.getDayOfWeek()==DayOfWeek.SUNDAY) multiplier=multiplier.max(new BigDecimal("1.20")); if((d.getMonth()==Month.DECEMBER && d.getDayOfMonth()>=24) || (d.getMonth()==Month.JANUARY && d.getDayOfMonth()==1)) multiplier=multiplier.max(new BigDecimal("1.50")); for(var rule: rules.findByActiveTrue()){ boolean inWindow=(rule.getStartsOn()==null||!d.isBefore(rule.getStartsOn())) && (rule.getEndsOn()==null||!d.isAfter(rule.getEndsOn())); boolean category=rule.getCategory()==null || rule.getCategory().getId().equals(product.getCategory().getId()); if(inWindow && category) multiplier=multiplier.max(rule.getMultiplier()); } total=total.add(product.getBasePricePerDay().multiply(multiplier)); } return new PriceQuote(product.getId(), start, end, total.setScale(2, RoundingMode.HALF_UP), notes.toString()); }
}
